        if (frac < 0) frac = 0;
        if (frac > 1) frac = 1;
        const pt = _pointOnPath(g, frac * N);
        const b = makePair(pt.x + perpX * halftick, pt.y + perpY * halftick);
        const c = makePair(pt.x - perpX * halftick, pt.y - perpY * halftick);
        const tp = makePath([lineSegment(b, c)], false);
