      const geoW = (geoMaxX - geoMinX) || 1;
      const geoH = (geoMaxY - geoMinY) || 1;
      roughPxPerUnit = Math.min(150 / geoW, 150 / geoH);
      roughPxPerUnitX = roughPxPerUnitY = roughPxPerUnit;
